// Ensure Alpha is valid for EMA (0 < alpha <= 1)
static_assert(RCOD_SMOOTHING_ALPHA > 0.0f && RCOD_SMOOTHING_ALPHA <= 1.0f, "Alpha must be in (0, 1]");
// Ensure Debounce is positive
